DROP TABLE IF EXISTS `caipiao_adminlog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_adminlog` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `userid` int(11) NOT NULL,
  `username` char(60) NOT NULL,
  `type` char(20) NOT NULL COMMENT 'login-đăng nhập, logout-đăng xuất, act-thao tác',
  `info` varchar(60) NOT NULL,
  `path` varchar(255) DEFAULT '' COMMENT 'Đường dẫn yêu cầu',
  `method` varchar(10) DEFAULT '' COMMENT 'Phương thức yêu cầu',
  `params` text COMMENT 'Tham số yêu cầu',
  `ip` char(20) NOT NULL,
  `iparea` varchar(60) NOT NULL COMMENT 'Khu vực IP',
  `time` int(11) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `userid` (`userid`)
) ENGINE=InnoDB AUTO_INCREMENT=342 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;
/*!40101 SET character_set_client = @saved_cs_client */;

